CREATE TABLE users (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(120) NOT NULL,email VARCHAR(120) NOT NULL UNIQUE,password_hash VARCHAR(255) NOT NULL,role VARCHAR(40) DEFAULT 'editor',active TINYINT(1) DEFAULT 1,created_at DATETIME,updated_at DATETIME);
CREATE TABLE news (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(200),summary TEXT,content MEDIUMTEXT,status VARCHAR(30) DEFAULT 'draft',image_path VARCHAR(255),published_at DATETIME NULL,created_at DATETIME,updated_at DATETIME);
CREATE TABLE councilors (id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(180),party VARCHAR(20),bio TEXT,status VARCHAR(30) DEFAULT 'active',photo_path VARCHAR(255),created_at DATETIME,updated_at DATETIME);
CREATE TABLE laws (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(200),law_type VARCHAR(30),number VARCHAR(40),summary TEXT,status VARCHAR(30) DEFAULT 'vigente',pdf_path VARCHAR(255),created_at DATETIME,updated_at DATETIME);
CREATE TABLE official_diary (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(200),edition_number VARCHAR(40),published_at DATETIME NULL,status VARCHAR(30) DEFAULT 'draft',pdf_path VARCHAR(255),created_at DATETIME,updated_at DATETIME);
CREATE TABLE esic_requests (id INT AUTO_INCREMENT PRIMARY KEY,protocol VARCHAR(40),requester_name VARCHAR(160),request_text TEXT,status VARCHAR(30) DEFAULT 'aberto',response_text TEXT,response_date DATETIME NULL,created_at DATETIME,updated_at DATETIME);
CREATE TABLE ombudsman_requests (id INT AUTO_INCREMENT PRIMARY KEY,protocol VARCHAR(40),type VARCHAR(50),requester_name VARCHAR(160),message TEXT,status VARCHAR(30) DEFAULT 'aberto',response_text TEXT,due_date DATE NULL,created_at DATETIME,updated_at DATETIME);
CREATE TABLE public_tenders (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(200),notice_number VARCHAR(50),description TEXT,status VARCHAR(30) DEFAULT 'aberto',notice_path VARCHAR(255),created_at DATETIME,updated_at DATETIME);
CREATE TABLE site_settings (id INT AUTO_INCREMENT PRIMARY KEY,setting_key VARCHAR(100) UNIQUE,setting_value TEXT,created_at DATETIME,updated_at DATETIME);
CREATE TABLE transparency_links (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(150),url VARCHAR(255),status VARCHAR(20) DEFAULT 'active',created_at DATETIME,updated_at DATETIME);
CREATE TABLE documents (id INT AUTO_INCREMENT PRIMARY KEY,title VARCHAR(200),doc_type VARCHAR(80),file_path VARCHAR(255),status VARCHAR(20) DEFAULT 'active',created_at DATETIME,updated_at DATETIME);
CREATE TABLE audit_logs (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,action VARCHAR(40),entity_type VARCHAR(80),entity_id INT NULL,payload JSON NULL,created_at DATETIME,INDEX(user_id));
